// Step 2 + 3 of the pods-order-validation skill.
// 1) Filter order.Lines on VALID_ITEM_CODES (read ItemCode, NOT ServiceCode).
// 2) Sort by Sequence ASC.
// 3) Build actualSequence using line.ServiceCode if non-empty,
//    else fall back to ITEM_TO_SERVICE mapping for that ItemCode.
// Returns { legLines, actualSequence, journeyType }. The CodeExecPlugin
// wraps this return value as {success, output={...this return...},
// stdout, stderr}, and the engine stores the ENTIRE envelope under the
// activity's single output variable (#legData). Downstream activities
// read fields via #legData.output.legLines / .actualSequence / .journeyType
// — this is the same envelope-unwrap pattern used by
// workflow-architect/templates/foreach-accumulate.json (see
// #details?.output there).
java.util.Set<String> VALID_ITEM_CODES = java.util.Set.of(
    "IDEL","RETSC","LDT","REDEL","FPU","MOV","SID","SFP","SCDEL","CSRED","CSFPU");
java.util.Map<String,String> ITEM_TO_SERVICE = java.util.Map.ofEntries(
    java.util.Map.entry("IDEL","NEW"), java.util.Map.entry("RETSC","WRT"),
    java.util.Map.entry("LDT","WTW"),  java.util.Map.entry("REDEL","RDL"),
    java.util.Map.entry("FPU","FPU"),  java.util.Map.entry("MOV","MOV"),
    java.util.Map.entry("SID","SID"),  java.util.Map.entry("SFP","SFP"),
    java.util.Map.entry("SCDEL","SCDEL"), java.util.Map.entry("CSRED","CSRED"),
    java.util.Map.entry("CSFPU","CSFPU"));
java.util.Map<String,Object> order = (java.util.Map<String,Object>) input.get("order");
java.util.List<java.util.Map<String,Object>> allLines =
    (java.util.List<java.util.Map<String,Object>>) order.getOrDefault("Lines", java.util.List.of());
java.util.List<java.util.Map<String,Object>> legs = new java.util.ArrayList<>();
for (java.util.Map<String,Object> l : allLines) {
  Object ic = l.get("ItemCode");
  if (ic != null && VALID_ITEM_CODES.contains(ic.toString())) legs.add(l);
}
legs.sort((a,b) -> {
  Number sa = (Number) a.getOrDefault("Sequence", 0);
  Number sb = (Number) b.getOrDefault("Sequence", 0);
  return Long.compare(sa.longValue(), sb.longValue());
});
java.util.List<String> seq = new java.util.ArrayList<>();
for (java.util.Map<String,Object> l : legs) {
  Object svc = l.get("ServiceCode");
  String s = (svc != null && !svc.toString().isBlank())
      ? svc.toString()
      : ITEM_TO_SERVICE.get(String.valueOf(l.get("ItemCode")));
  if (s != null) seq.add(s);
}
// journeyType: prefer top-level order.OrderType, fall back to the first
// line's OrderType (PODS orders observed in stage have OrderType per-line
// but not always at the order root). Skill prose says "from order" but
// in practice the source-of-truth varies by API revision.
String journeyType = "";
Object orderTop = order.get("OrderType");
if (orderTop != null && !orderTop.toString().isBlank()) {
  journeyType = orderTop.toString();
} else {
  for (java.util.Map<String,Object> l : allLines) {
    Object lt = l.get("OrderType");
    if (lt != null && !lt.toString().isBlank()) { journeyType = lt.toString(); break; }
  }
}
java.util.Map<String,Object> out = new java.util.LinkedHashMap<>();
out.put("legLines", legs);
out.put("actualSequence", seq);
out.put("journeyType", journeyType);
return out;

// Step 4 accumulator: append one entry per leg line. If origin or
// destination is missing on the current leg, record a skipped entry
// instead of dropping the leg silently. serviceabilityResults must end
// up with exactly legLines.size() entries.
//
// FAILURE RULE: a leg is marked NOT serviceable ONLY when the
// Serviceability tool's CallInfo.StatusCode contains "OutOfMarket"
// (i.e. "OutOfMarket-Origination", "OutOfMarket-Destination", or
// "OutOfMarket-Both"). Everything else (e.g. "PastDate",
// non-OutOfMarket warnings, empty status) is treated as serviceable —
// the business does not want PastDate-style soft signals to flip a
// validation to failed.
java.util.List<Object> acc = new java.util.ArrayList<>();
if (input.get("acc") instanceof java.util.List<?> existing) {
  for (Object o : existing) acc.add(o);
}
java.util.Map<String,Object> leg = (java.util.Map<String,Object>) input.get("leg");
java.util.Map<String,Object> svc = (java.util.Map<String,Object>) input.get("svc");
// Pull the origin/destination postal codes off the leg's Addresses list so
// the UI can render them in the per-line serviceability table without
// re-walking the order. Tolerant of missing/empty entries.
String originZip = null;
String destinationZip = null;
if (leg != null) {
  java.util.List<java.util.Map<String,Object>> addrs =
      (java.util.List<java.util.Map<String,Object>>) leg.getOrDefault("Addresses", java.util.List.of());
  for (java.util.Map<String,Object> a : addrs) {
    Object t = a.get("AddressType");
    Object zip = a.get("PostalCode");
    if (zip == null) continue;
    if ("Origination".equals(String.valueOf(t))) originZip = zip.toString();
    else if ("Destination".equals(String.valueOf(t))) destinationZip = zip.toString();
  }
}
java.util.Map<String,Object> entry = new java.util.LinkedHashMap<>();
entry.put("lineId", leg == null ? null : leg.get("LineIdentity"));
entry.put("itemCode", leg == null ? null : leg.get("ItemCode"));
entry.put("originZip", originZip);
entry.put("destinationZip", destinationZip);
if (svc != null) {
  java.util.Map<String,Object> callInfo =
      (java.util.Map<String,Object>) svc.getOrDefault("CallInfo", java.util.Map.of());
  Object statusCodeObj = callInfo.get("StatusCode");
  String statusCode = statusCodeObj == null ? "" : statusCodeObj.toString();
  boolean outOfMarket = statusCode != null && statusCode.contains("OutOfMarket");
  entry.put("isServiceable", !outOfMarket);
  entry.put("exceptionType", outOfMarket ? statusCode : null);
  entry.put("status", "checked");
} else {
  entry.put("status", "skipped");
  entry.put("reason", "missing addresses or Serviceability call failed");
}
acc.add(entry);
return acc;

// Step 5: build toCheck = IDEL lines from order.Lines (NOT legLines)
// that are missing ContainerId or ScheduledDate and have NOT already
// been delivered. If toCheck is empty the foreach below naturally
// produces zero invocations and containerAvailability stays empty.
//
// We ALSO pre-compute each line's `_referenceDate` (ScheduledDate if
// set, else today as ISO date) here in Java rather than in the SpEL
// expression on callContainerAvailability. The engine's SpEL sandbox
// forbids T(...) type references, so `T(java.time.LocalDate).now()`
// fires "Access to types is forbidden" at PARSE time — short-circuit
// via `?:` can't save it because the guard runs before short-circuit.
// Pre-computing here means the downstream SpEL only needs a property
// read.
String todayIso = java.time.LocalDate.now().toString();
java.util.Map<String,Object> order = (java.util.Map<String,Object>) input.get("order");
java.util.List<java.util.Map<String,Object>> allLines =
    (java.util.List<java.util.Map<String,Object>>) order.getOrDefault("Lines", java.util.List.of());
java.util.List<Object> toCheck = new java.util.ArrayList<>();
for (java.util.Map<String,Object> l : allLines) {
  if (!"IDEL".equals(String.valueOf(l.get("ItemCode")))) continue;
  Object deliveryDate = l.get("DeliveryDate");
  if (deliveryDate != null && !deliveryDate.toString().isBlank()) continue;
  Object containerId   = l.get("ContainerId");
  Object scheduledDate = l.get("ScheduledDate");
  boolean missing = (containerId == null || containerId.toString().isBlank())
                 || (scheduledDate == null || scheduledDate.toString().isBlank());
  if (missing) {
    java.util.Map<String,Object> enriched = new java.util.LinkedHashMap<>(l);
    enriched.put("_referenceDate",
        (scheduledDate != null && !scheduledDate.toString().isBlank())
            ? scheduledDate.toString() : todayIso);
    toCheck.add(enriched);
  }
}
return toCheck;

// Step 5 accumulator: collect one entry per toCheck line.
java.util.List<Object> acc = new java.util.ArrayList<>();
if (input.get("acc") instanceof java.util.List<?> existing) {
  for (Object o : existing) acc.add(o);
}
java.util.Map<String,Object> line = (java.util.Map<String,Object>) input.get("line");
java.util.Map<String,Object> ca = (java.util.Map<String,Object>) input.get("ca");
java.util.Map<String,Object> entry = new java.util.LinkedHashMap<>();
entry.put("lineId", line == null ? null : line.get("LineIdentity"));
entry.put("itemCode", "IDEL");
entry.put("checked", ca != null);
java.util.List<Object> availableDates = new java.util.ArrayList<>();
// Capture the first reason code that blocked each date, so the UI can
// surface *why* a line shows no availability. We pick the first non-blank
// reason rather than aggregating because the user just needs a label.
String firstReason = null;
if (ca != null) {
  java.util.List<java.util.Map<String,Object>> dates =
      (java.util.List<java.util.Map<String,Object>>) ca.getOrDefault("GeneralAvailabilityDates", java.util.List.of());
  for (java.util.Map<String,Object> d : dates) {
    Object avail = d.get("IsAvailableCS");
    Object reason = d.get("ReasonCode");
    boolean isAvailable = Boolean.TRUE.equals(avail);
    boolean noReason = (reason == null) || reason.toString().isBlank();
    if (isAvailable && noReason) {
      availableDates.add(d.get("DateValue"));
    } else if (firstReason == null && !noReason) {
      firstReason = reason.toString();
    }
  }
}
entry.put("availableDates", availableDates);
if (ca == null) {
  entry.put("skipReason", "ContainerAvailability call failed or returned no payload");
} else if (availableDates.isEmpty() && firstReason != null) {
  entry.put("skipReason", firstReason);
}
acc.add(entry);
return acc;
